1	type Item = { type: string };
2	type Scenario = { steps: Array<{ items: Item[] }> };
3	
4	const PROCESSING_FEE = 5;
5	
6	const PREMIUM_FOR_SINGLE_ITEM: Record<string, number> = {
7	  amulet: 71,
8	  staff: 93,
9	  potion: 49,
10	  sword: 115,
11	  rune: 33,
12	};
13	
14	const PREMIUM_FOR_TWO_RUNES = 60;
15	const PREMIUM_FOR_THREE_RUNES = 71;
16	
17	export function runScenario(input: unknown): unknown {
18	  const { steps } = input as Scenario;
19	  const premium = computePremium(steps[0].items);
20	  return { results: [{ premium }] };
21	}
22	
23	function computePremium(items: Item[]): number {
24	  if (items.length === 0) return PROCESSING_FEE;
25	  if (items.length === 3 && items.every(isRune)) return PREMIUM_FOR_THREE_RUNES;
26	  if (items.length === 2 && items[0].type === "rune") return PREMIUM_FOR_TWO_RUNES;
27	  return PREMIUM_FOR_SINGLE_ITEM[items[0].type];
28	}
29	
30	function isRune(item: Item): boolean {
31	  return item.type === "rune";
32	}
33

